router.post('/session/cleanup', async (c: any) => {

    let body: any = {};
    try {
      const contentType = c.req.header('content-type') || '';
      if (contentType.includes('application/json')) {
        body = await c.req.json();
      } else if (contentType) {
        body = await c.req.parseBody();
      }
    } catch(e) {}
    
    const req: any = {
      body,
      query: c.req.query(),
      params: c.req.param(),
      headers: c.req.header(),
      path: c.req.path
    };
    
    const res: any = {
      json: (d: any) => c.json(d),
      status: (s: any) => ({ json: (d: any) => c.json(d, s) }),
      sendStatus: (s: any) => c.body(null, s),
      setHeader: (k: string, v: string) => c.header(k, v)
    };
    const next = (err?: any) => { if(err) throw err; };
  try {
    // sendBeacon sends as text/plain — parse manually if needed
    let body = req.body;
    if (typeof body === 'string') {
      try { body = JSON.parse(body); } catch { return res.sendStatus(400); }
    }
    
    // Explicitly parse body if it is empty because of express.text() or no middleware
    if (Buffer.isBuffer(body)) {
      try { body = JSON.parse(body.toString()); } catch {}
    } else if (!body || Object.keys(body).length === 0) {
      // Try parsing from raw string if body-parser didn't catch it
      return res.sendStatus(400); 
    }

    const { sessionId, reason } = body;
    if (!sessionId) return res.sendStatus(400);
    
    // Run cleanup — do not await non-critical parts for response
    await runFullSessionCleanup(sessionId, reason);
    
    // sendBeacon doesn't care about the response body, but must get 204
    res.sendStatus(204);
  } catch (err) {
    console.error('[Session Cleanup Endpoint Error]:', err);
    res.sendStatus(500);
  }
});
router.post('/session/heartbeat', async (c: any) => {

    let body: any = {};
    try {
      const contentType = c.req.header('content-type') || '';
      if (contentType.includes('application/json')) {
        body = await c.req.json();
      } else if (contentType) {
        body = await c.req.parseBody();
      }
    } catch(e) {}
    
    const req: any = {
      body,
      query: c.req.query(),
      params: c.req.param(),
      headers: c.req.header(),
      path: c.req.path
    };
    
    const res: any = {
      json: (d: any) => c.json(d),
      status: (s: any) => ({ json: (d: any) => c.json(d, s) }),
      sendStatus: (s: any) => c.body(null, s),
      setHeader: (k: string, v: string) => c.header(k, v)
    };
    const next = (err?: any) => { if(err) throw err; };
  try {
    const { sessionId, sessionToken, clientState } = req.body;
    if (!sessionId || !sessionToken) {
      return res.status(400).json({ error: 'sessionId and sessionToken are required' });
    }
    
    const supabase = getSupabase();
    const { data: session, error: fetchErr } = await supabase
      .from('visitor_sessions')
      .select('status, match_id')
      .eq('id', sessionId)
      .eq('session_token', sessionToken)
      .single();
      
    if (fetchErr) throw new AppError(401, 'Invalid session');

    // V9 State Synchronization Guardrail
    // If frontend thinks it is READY or SEARCHING, but DB thinks it is matched, we have a desync.
    if (clientState && ['READY', 'SEARCHING', 'REQUEUEING'].includes(clientState)) {
      if (['RESERVED', 'READY', 'CONNECTED'].includes(session.status) && session.match_id) {
        console.warn(`[Sync Guardrail] Desync detected for ${sessionId}: Client is ${clientState}, DB is ${session.status}. Forcing cleanup.`);
        
        // Notify the ghost partner that this user has left
        const { data: matchInfo } = await supabase
          .from('matches')
          .select('user_a, user_b')
          .eq('id', session.match_id)
          .single();
          
        if (matchInfo) {
          const partnerId = matchInfo.user_a === sessionId ? matchInfo.user_b : matchInfo.user_a;
          await broadcastToSession(partnerId, 'partner_left', { reason: 'desync_recovery' });
        }
        
        // Destroy the ghost match
        await supabase.from('matches').update({ status: 'ended', ended_at: new Date().toISOString() }).eq('id', session.match_id);
        
        // Reset this user to READY (they will be re-queued by the frontend if they are SEARCHING)
        await supabase.from('visitor_sessions').update({ status: 'READY', match_id: null }).eq('id', sessionId);
      }
    }

    const { error } = await supabase
      .from('visitor_sessions')
      .update({ last_activity: new Date().toISOString() })
      .eq('id', sessionId);
      
    if (error) throw error;
    return res.json({ success: true });
  } catch (err: any) {
    return c.json({ error: err.message || 'Internal error' }, 500);
  }
});
